css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: #0a0f14; font-family: -apple-system, BlinkMacSystemFont, monospace; display: flex; align-items: center; justify-content: center; color: white; padding: 20px; }
.game { width: 100%; max-width: 760px; }
.header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 28px; }
h1 { font-size: 28px; font-weight: 900; }
.stats { display: flex; gap: 16px; }
.stat-box { background: rgba(255,255,255,0.06); border-radius: 12px; padding: 12px 20px; text-align: center; min-width: 80px; } .stat-box span { display: block; font-size: 11px; color: #6b7280; margin-bottom: 2px; font-family: sans-serif; } .stat-box strong { font-size: 24px; font-weight: 800; }
.text-display { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 16px; padding: 24px; font-size: 18px; line-height: 1.9; letter-spacing: 0.5px; margin-bottom: 16px; color: #4b5563; user-select: none; min-height: 120px; }
.char { display: inline; }
.char.correct { color: #22c55e; }
.char.wrong { color: #ef4444; background: rgba(239,68,68,0.15); border-radius: 2px; }
.char.current { background: rgba(6,182,212,0.3); color: #06b6d4; border-radius: 2px; }
.type-area { width: 100%; height: 80px; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.12); border-radius: 14px; color: white; font-size: 16px; padding: 16px 20px; outline: none; resize: none; font-family: monospace; letter-spacing: 0.5px; transition: border-color 0.2s; margin-bottom: 16px; } .type-area:focus { border-color: rgba(6,182,212,0.5); }
.controls { display: flex; justify-content: space-between; align-items: center; }
.restart-btn { padding: 12px 24px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.15); background: transparent; color: white; font-size: 14px; font-weight: 600; cursor: pointer; transition: all 0.2s; } .restart-btn:hover { background: rgba(255,255,255,0.08); }
.difficulty { display: flex; gap: 8px; }
.diff-btn { padding: 10px 18px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.12); background: transparent; color: #6b7280; font-size: 13px; font-weight: 600; cursor: pointer; transition: all 0.2s; } .diff-btn.active { background: rgba(6,182,212,0.15); border-color: #06b6d4; color: #06b6d4; }
.result { position: fixed; inset: 0; background: rgba(0,0,0,0.85); display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 24px; backdrop-filter: blur(10px); }
.result h2 { font-size: 36px; font-weight: 900; }
.result-stats { display: flex; gap: 32px; } .result-stats div { text-align: center; background: rgba(255,255,255,0.07); padding: 20px 28px; border-radius: 16px; } .result-stats span { display: block; color: #6b7280; font-size: 13px; margin-bottom: 6px; } .result-stats strong { font-size: 36px; font-weight: 900; color: #06b6d4; }
.result button { padding: 16px 40px; border-radius: 14px; border: none; background: #06b6d4; color: white; font-size: 16px; font-weight: 800; cursor: pointer; }

