const texts = {
  easy: ['Merhaba dünya bu basit bir yazma testi metnidir ve hızınızı ölçmek için kullanılır', 'Bugün hava çok güzel ve dışarıda yürüyüş yapmak için harika bir gün gibi görünüyor', 'Yazılım geliştirme modern dünyada en önemli becerilerden biri haline gelmiştir'],
  medium: ['React ile geliştirilen modern web uygulamaları kullanıcı deneyimini önemli ölçüde artırmaktadır', 'JavaScript programlama dili hem frontend hem de backend geliştirme için kullanılan çok yönlü bir dildir', 'Algoritma ve veri yapıları bilgisayar biliminin temel konuları arasında yer almaktadır'],
  hard: ['Asenkron programlama paradigması Promise ve async await sözdizimi ile JavaScript üzerinde kolayca uygulanabilmektedir', 'Makine öğrenmesi modelleri büyük veri setleri üzerinde eğitilerek karmaşık örüntüleri öğrenebilmektedir', 'Mikroservis mimarisi monolitik yapıların aksine bağımsız olarak dağıtılabilen servislerden oluşmaktadır']
};
let words = [], typed = 0, errors = 0, started = false, finished = false, timeLeft = 60, interval = null, diff = 'easy';
function setDiff(d, btn) {
  diff = d;
  document.querySelectorAll('.diff-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  restart();
}
function restart() {
  clearInterval(interval);
  started = false; finished = false; typed = 0; errors = 0; timeLeft = 60;
  document.getElementById('wpm').textContent = '0';
  document.getElementById('acc').textContent = '100%';
  document.getElementById('timer').textContent = '60';
  document.getElementById('type-area').value = '';
  document.getElementById('type-area').disabled = false;
  document.getElementById('result').style.display = 'none';
  const text = texts[diff][Math.floor(Math.random() * texts[diff].length)];
  words = text.split('');
  document.getElementById('text-display').innerHTML = words.map((c, i) => `<span class="char" id="c${i}">${c === ' ' ? '&nbsp;' : c}</span>`).join('');
  document.getElementById('c0').classList.add('current');
}
function startIfNeeded() {
  if (!started && !finished) {
    started = true;
    interval = setInterval(() => {
      timeLeft--;
      document.getElementById('timer').textContent = timeLeft;
      if (timeLeft <= 0) finish();
    }, 1000);
  }
}
function check() {
  if (finished) return;
  const input = document.getElementById('type-area').value;
  const current = input[input.length - 1];
  if (!current) return;
  const expected = words[typed];
  document.getElementById('c' + typed).classList.remove('current', 'correct', 'wrong');
  if (current === expected) {
    document.getElementById('c' + typed).classList.add('correct');
  } else {
    document.getElementById('c' + typed).classList.add('wrong');
    errors++;
  }
  typed++;
  if (typed < words.length) document.getElementById('c' + typed).classList.add('current');
  document.getElementById('type-area').value = '';
  const elapsed = 60 - timeLeft;
  if (elapsed > 0) {
    const wpm = Math.round((typed / 5) / (elapsed / 60));
    document.getElementById('wpm').textContent = wpm;
  }
  const acc = Math.round(((typed - errors) / Math.max(typed, 1)) * 100);
  document.getElementById('acc').textContent = acc + '%';
  if (typed >= words.length) finish();
}
function finish() {
  clearInterval(interval); finished = true;
  document.getElementById('type-area').disabled = true;
  const elapsed = 60 - timeLeft || 1;
  const wpm = Math.round((typed / 5) / (elapsed / 60));
  const acc = Math.round(((typed - errors) / Math.max(typed, 1)) * 100);
  document.getElementById('r-wpm').textContent = wpm;
  document.getElementById('r-acc').textContent = acc + '%';
  document.getElementById('r-words').textContent = typed;
  document.getElementById('r-errors').textContent = errors;
  document.getElementById('result').style.display = 'flex';
}
restart();
